class Playground {
    async run(inputs) {
        // Parse inputs
        const nums = JSON.parse(inputs[0]);
        const target = parseInt(inputs[1]);
        // Initialize visual slots
        this.nums.init(nums);
        this.map.init([]);
        this.vars.init([]);
        // Store target in variables slot for display
        this.vars.put('target', target);
        this.log('Start scanning the array for a pair that sums to ' + target);
        await this.await();
        for (let i = 0; i < nums.length; i++) {
            const val = this.nums.get(i);
            // Highlight current index
            this.nums.highlight(i, '#ffb703');
            this.vars.put('i', i);
            this.vars.put('val', val);
            this.log(`Inspect index ${i}, value ${val}`);
            await this.await();
            const complement = target - val;
            this.vars.put('complement', complement);
            this.log(`Looking for complement ${complement} in map`);
            await this.await();
            if (this.map.has(complement)) {
                const j = this.map.get(complement);
                this.log(`Found! indices ${j} and ${i} sum to ${target}`);
                // Highlight both indices
                this.nums.highlight(j, '#00e0ff');
                this.nums.highlight(i, '#00e0ff');
                await this.await();
                return [j, i];
            }
            // Not found, store current value
            this.map.put(val, i);
            this.log(`Store value ${val} with index ${i} in map`);
            // Highlight map entry (using key color)
            this.map.highlight(val, '#6c8cff');
            await this.await();
        }
        this.log('No pair found (should not happen per problem constraints)');
        await this.await();
        return null;
    }
}
